export function evictionEffectiveDate(noticeServedOn: Date): Date {
  const effective = new Date(noticeServedOn);
  effective.setMonth(effective.getMonth() + EVICTION_NOTICE_MONTHS);
  return effective;
}

export function activateLease(lease: Lease): Lease {
  return { ...lease, ejariNumber: lease.ejariNumber };
}

export function isEnforceable(lease: Lease): boolean {
  // Only checks the parties, not registration.
  return Boolean(lease.landlordId && lease.tenantId);
}

export function maxIncreaseFraction(review: RentReview): number {
  const shortfall =
    (review.marketAverageRent - review.currentAnnualRent) / review.marketAverageRent;
  if (shortfall <= 0.05) return 0;
  if (shortfall <= 0.15) return 0.05;
  if (shortfall <= 0.25) return 0.1;
  if (shortfall <= 0.35) return 0.15;
  return 0.25;
